#!/usr/bin/env python3
"""Batch 3 — ~250 Ink strings (Nozi/Atomic Heart investigation/Mateo/Eliisabet/Llhor)."""
import csv

T = {
    "I was asked by Citra to gather some glowworms.": "Citra mi ha chiesto di raccogliere dei vermi luminosi.",
    "Ask around at Seven Sisters Station to find out how to catch glowworms.": "Chiedere in giro alla Stazione Sette Sorelle come catturare i vermi luminosi.",
    "I asked around and learned that the worms nest in a cave in Hakoa. I'll need to smoke them out by throwing the rocks in the caves into water.": "Ho chiesto in giro e ho scoperto che i vermi si annidano in una grotta a Hakoa. Devo affumicarli lanciando le rocce della grotta nell'acqua.",
    "Head to the cave.": "Vai alla grotta.",
    "Gather glowworms - ": "Raccogli vermi luminosi - ",
    "/": "/",
    "Give the glowworms to Citra.": "Consegna i vermi luminosi a Citra.",
    "I gave the glowworms to Citra.": "Ho consegnato i vermi luminosi a Citra.",
    "I should probably check back in with Sandip to see if the new powercore is ready.": "Forse dovrei tornare da Sandip per vedere se il nuovo nucleo di potenza è pronto.",
    "There's a slot for a keycard on the terminal. Perhaps this would unlock the door?": "C'è una fessura per una tessera sul terminale. Forse sbloccherà la porta?",
    "Insert keycard.": "Inserisci la tessera.",
    "Do nothing.": "Non fare nulla.",
    "I insert the keycard and the door unlocks.": "Inserisco la tessera e la porta si sblocca.",
    "Maybe I should leave this alone.": "Forse è meglio lasciar perdere.",
    '<<"You! It was you!">>': '<<"Tu! Sei stata tu!">>',
    "I am slightly shocked by the force of the accusation, however true it may be.": "Sono leggermente scossa dalla forza dell'accusa, per quanto possa essere vera.",
    "I can only stare back in a shocked silence. He looks like he's had a rough time. Did he resist the Guards?": "Posso solo restare a fissarlo in un silenzio scioccato. Sembra averla passata male. Ha resistito alle Guardie?",
    '<<"I can tell just by looking at you, <i>you</i> put me here! I told you! I was at the Cafe, Rita must have confirmed it.">>': '<<"Si capisce solo guardandoti, sei <i>tu</i> che mi hai messo qui! Te l\'ho detto! Ero al Caffè, Rita deve averlo confermato.">>',
    '<<"You put me here anyway... nobody cares if an old Serai Climber goes in front of the Witnesses. Nobody.">>': '<<"Mi ci hai messo lo stesso... a nessuno importa se un vecchio Scalatore del Serai finisce davanti ai Testimoni. A nessuno.">>',
    '<<"You\'ve damned me, you\'ve set up an innocent person.">>': '<<"Mi hai dannato, hai incastrato un innocente.">>',
    '<<"I hope you can live with yourself, Glider.">>': '<<"Spero che tu riesca a convivere con te stessa, Glider.">>',
    "A cold feeling washes over me, did I make a mistake? I don't feel good about it. Surely Sandip wouldn't just go along with what I said even if it was wrong?": "Mi pervade una sensazione di freddo, ho commesso un errore? Non mi sento bene. Sandip non andrebbe certo dietro a ciò che ho detto se fosse sbagliato, vero?",
    "Hamza looks slightly disheveled, he hasn't been handled lightly it seems.": "Hamza sembra leggermente provato, non l'hanno trattato con i guanti, a quanto pare.",
    "I can't tell if he notices my approach. He doesn't acknowledge me if he does.": "Non capisco se si accorga del mio avvicinarmi. Se anche lo nota, non lo dà a vedere.",
    '<<"Hello, Glider. Sable, was it?">>': '<<"Ciao, Glider. Sable, giusto?">>',
    '<<"So you worked it out did you? Feeling good about yourself, I suppose. I guess I would be feeling pretty smug myself, I hope it was a challenge to work out, at least.">>': '<<"Quindi ci sei arrivata, eh? Ti senti bene con te stessa, immagino. Anch\'io sarei piuttosto compiaciuto, spero almeno che sia stata una bella sfida.">>',
    "It seems I got the right guy, at least. His resigned demeanour is making me wonder if it was right to point that out, however.": "Pare almeno che abbia preso l'uomo giusto. Il suo atteggiamento rassegnato però mi fa chiedere se sia stato giusto denunciarlo.",
    '<<"Well, Iria got her money back and then some with me out the way. Good luck to the poor soul they bring in to replace me, if they aren\'t one of her picks she\'ll have her hooks into them soon enough.">>': '<<"Beh, Iria si è ripresa i suoi soldi e qualcosa di più togliendomi di mezzo. Buona fortuna alla povera anima che porteranno a sostituirmi: se non è una delle sue raccomandate, avrà i suoi artigli addosso presto.">>',
    "The air fills with silence once again. He seems to have said his piece.": "L'aria si riempie di nuovo di silenzio. Sembra aver detto la sua.",
    "I turn to leave him finally, the Witnesses will be the arbiters of his fate from here. A glint in the air catches my eye as I do so and I instinctively grab at it.": "Mi volto finalmente per lasciarlo, i Testimoni saranno i giudici del suo destino da qui in poi. Mentre lo faccio un luccichio nell'aria mi attira lo sguardo e istintivamente lo afferro.",
    "A metallic object, heavy in the hand. I realise what it is after a moment. ": "Un oggetto metallico, pesante in mano. Capisco cos'è dopo un momento. ",
    "I look up in surprise, Hamza stares at me and nods his head silently.": "Alzo lo sguardo sorpresa, Hamza mi fissa e annuisce in silenzio.",
    "Yannis looks surprisingly well for a man clearly taking the fall for someone else. Its a little unsettling.": "Yannis sembra sorprendentemente in forma per essere uno che si sta chiaramente accollando le colpe di qualcun altro. È un po' inquietante.",
    '<<"Oh, hello my friend.">>': '<<"Oh, ciao amica mia.">>',
    "Something about the way he spits the word 'friend' makes me feel like he's being insincere.": "Qualcosa nel modo in cui pronuncia la parola 'amica' mi fa sentire che è insincero.",
    '<<"A little tip for a good friend.">>': '<<"Un piccolo consiglio per una buona amica.">>',
    '<<"I would consider very carefully how long you stick around in Eccria, Sable.">>': '<<"Valuterei con molta attenzione quanto tempo restare a Eccria, Sable.">>',
    "The sound of my name echoing against the metal of his mask sends an immediate shudder through my body. I'm starting to feel like I might have made a huge mistake.": "Il suono del mio nome che echeggia contro il metallo della sua maschera mi manda un brivido immediato lungo il corpo. Comincio a sentire che potrei aver commesso un enorme errore.",
    "At least the Witnesses should keep him busy whilst I'm on my Gliding. I'll have to think carefully about returning in the future, however.": "Almeno i Testimoni dovrebbero tenerlo occupato mentre sono in Volo. Dovrò però pensarci bene prima di tornare in futuro.",
    "I decide to not spend any more time than I have to with him.": "Decido di non passare con lui più tempo del necessario.",
    "Plain as day, one can see that the high window has been smashed, and it's wide enough for any grown person to make their way inside-- though they'd need to be quite athletic. Most of the glass is on the outside of the chamber, it may have been smashed from inside.": "Chiaro come il sole, si vede che la finestra alta è stata frantumata, ed è abbastanza larga perché ci passi un adulto-- anche se dovrebbe essere piuttosto atletico. La maggior parte del vetro è all'esterno della camera: potrebbe essere stata rotta dall'interno.",
    "There is a clump of feathers on the floor. Strange.": "C'è un ciuffo di piume sul pavimento. Strano.",
    "I try to picture the bird large and powerful enough to carry away the powercore, and decide that it is one suspect I can absolutely rule out. Though I would very much like to see it.": "Cerco di immaginare un uccello abbastanza grande e potente da portare via il nucleo di potenza, e decido che è un sospetto che posso assolutamente escludere. Anche se mi piacerebbe molto vederlo.",
    "Now this is a clue!": "Adesso sì che è un indizio!",
    "A scrap of paper lies discarded on the floor, and when I take it up I see that it's a promissory note: somebody, perhaps the culprit, owes money to the Merchants.": "Un pezzetto di carta giace abbandonato sul pavimento, e quando lo raccolgo vedo che è un pagherò: qualcuno, forse il colpevole, deve dei soldi ai Mercanti.",
    "It's possible the culprit dropped it, but who could be so careless at the scene of their crime? I wonder if it's a plant, left to throw me off the scene.": "È possibile che il colpevole l'abbia perso, ma chi potrebbe essere così sbadato sulla scena del proprio crimine? Mi chiedo se sia un'esca, lasciata per depistarmi.",
    "Sparks shoot out from the wires around the socket but the damage to the empty socket itself is non-existent as far as I can tell.": "Scintille schizzano dai cavi attorno all'alloggiamento, ma il danno all'alloggiamento vuoto in sé è inesistente, per quanto posso giudicare.",
    "The culprit took good care in removing the core. It makes sense. If I were to steal something so valuable I would be delicate, too. But why the torn up cables? It looks almost staged to me.": "Il colpevole ha rimosso il nucleo con cura. Ha senso. Se dovessi rubare qualcosa di così prezioso, anch'io sarei delicata. Ma perché i cavi strappati? Mi sembra quasi una messinscena.",
    "There are no signs of damage to the socket, so far as I can tell. The culprit took good care in removing the core. It makes sense. If I were to steal something so valuable, I would be delicate, too.": "Non ci sono segni di danno all'alloggiamento, per quanto posso vedere. Il colpevole ha rimosso il nucleo con cura. Ha senso. Se dovessi rubare qualcosa di così prezioso, anch'io sarei delicata.",
    "Install the new core.": "Installa il nuovo nucleo.",
    "Step away.": "Allontanati.",
    "I slot the new core into the socket. The sound is satisfying.": "Inserisco il nuovo nucleo nell'alloggiamento. Il suono è appagante.",
    "I step away from the socket.": "Mi allontano dall'alloggiamento.",
    "Inspect the Core socket": "Ispeziona l'alloggiamento del Nucleo",
    "Inspect smashed window": "Ispeziona la finestra rotta",
    "Inspect feathers on the floor": "Ispeziona le piume sul pavimento",
    "Inspect scrap of paper": "Ispeziona il pezzo di carta",
    " *** THE POWER COMES BACK ON *** ": " *** L'ENERGIA TORNA *** ",
    "<b>Suspects in the investigation:</b>": "<b>Sospetti nell'indagine:</b>",
    "Hamza is the town Machinist. Does his story hold up?": "Hamza è il Macchinista cittadino. La sua storia regge?",
    "Iria runs the Market in Eccria, could she be involved in the loss of power?": "Iria gestisce il Mercato di Eccria, potrebbe essere coinvolta nel guasto?",
    "Garay is part of the Serai, and lives under the bridge going into Eccria. Is he the culprit?": "Garay fa parte del Serai, e vive sotto il ponte che porta a Eccria. È lui il colpevole?",
    "<b>Physical evidence in the investigation:</b>": "<b>Prove fisiche nell'indagine:</b>",
    "A scrap of paper lies discarded on the floor, and when I take it up I see that it's a promissory note: somebody, perhaps the culprit, owes money to the Merchants. It's possible the culprit dropped it, but who could be so careless at the scene of their crime? I wonder if it's a plant, left to throw me off the scene.": "Un pezzetto di carta giace abbandonato sul pavimento, e quando lo raccolgo vedo che è un pagherò: qualcuno, forse il colpevole, deve dei soldi ai Mercanti. È possibile che il colpevole l'abbia perso, ma chi potrebbe essere così sbadato sulla scena del proprio crimine? Mi chiedo se sia un'esca, lasciata per depistarmi.",
    "A large feather inside the core chamber, it feels like a distraction but it could be a clue?": "Una grande piuma dentro la camera nucleare; sembra una distrazione ma potrebbe essere un indizio?",
    "The culprit took good care in removing the core. It makes sense. If I were to steal something so valuable, I would be delicate, too. But why the torn up cables? It looks almost staged to me.": "Il colpevole ha rimosso il nucleo con cura. Ha senso. Se dovessi rubare qualcosa di così prezioso, anch'io sarei delicata. Ma perché i cavi strappati? Mi sembra quasi una messinscena.",
    "<b>Quest events:</b>": "<b>Eventi della missione:</b>",
    "I spoke to Sandip, a guard in Eccria. He wants me to help with the investigation into the Atomic Heart - the Eccrine power station that's been recently sabotaged.": "Ho parlato con Sandip, una guardia di Eccria. Vuole che aiuti con l'indagine sul Cuore Atomico — la centrale eccrina che è stata recentemente sabotata.",
    "Deliver the new powercore to Hamza, the Machinist in Eccria.": "Consegna il nuovo nucleo di potenza a Hamza, il Macchinista di Eccria.",
    "I delivered the spare powercore to Hamza for repairs.": "Ho consegnato il nucleo di scorta a Hamza per le riparazioni.",
    "Check with Sandip to see if the spare powercore is ready.": "Controlla con Sandip se il nucleo di scorta è pronto.",
    "Sandip gave me a replacement powercore for the Atomic Heart, as well as a key for the door.": "Sandip mi ha dato un nucleo di potenza di ricambio per il Cuore Atomico, e anche una chiave per la porta.",
    "Follow the giant cable from Eccria to the Atomic Heart.": "Segui il cavo gigante da Eccria fino al Cuore Atomico.",
    "I found my way to the Atomic Heart.": "Ho trovato la strada per il Cuore Atomico.",
    "Install the new powercore in the Atomic Heart.": "Installa il nuovo nucleo nel Cuore Atomico.",
    "I installed the replacement core and the power came back.": "Ho installato il nucleo di ricambio e l'energia è tornata.",
    "I should return to Sandip now that the power is back.": "Dovrei tornare da Sandip ora che l'energia è tornata.",
    "I returned to Eccria and spoke to Sandip after the power came back on.": "Sono tornata a Eccria e ho parlato con Sandip dopo il ritorno dell'energia.",
    "Ask around Eccria for information about the power cut.": "Chiedi in giro a Eccria informazioni sul blackout.",
    "When I'm ready to make an accusation, I should speak to Sandip.": "Quando sono pronta per fare un'accusa, dovrei parlare con Sandip.",
    "Sandip and I decided it was Hamza who sabotaged the Atomic Heart. Sandip arrested him for his crimes.": "Sandip e io abbiamo deciso che è stato Hamza a sabotare il Cuore Atomico. Sandip lo ha arrestato per i suoi crimini.",
    "Sandip and I decided it was Garay who sabotaged the Atomic Heart. Sandip arrested him for his crimes.": "Sandip e io abbiamo deciso che è stato Garay a sabotare il Cuore Atomico. Sandip lo ha arrestato per i suoi crimini.",
    "Sandip and I decided it was Iria who sabotaged the Atomic Heart. Sandip was too afraid to arrest her, though.": "Sandip e io abbiamo deciso che è stata Iria a sabotare il Cuore Atomico. Sandip però aveva troppa paura per arrestarla.",

    # Mateo / Train / Camels / Shepherd
    "<<Young glider, I need your help getting back on my feet.>>": "<<Giovane glider, ho bisogno del tuo aiuto per rimettermi in piedi.>>",
    "<<Would you like to trade 1000 cuts?>>": "<<Vuoi scambiare 1000 cuts?>>",
    "Sure.": "Certo.",
    "Not right now.": "Non adesso.",
    "<<Great! Thanks for your patronage.>> ": "<<Ottimo! Grazie per la collaborazione.>> ",
    "<<Ah. Well; whenever you're ready, then.>>": "<<Ah. Bene; quando sei pronta, allora.>>",
    "<<I don't know what I'm to do!>>": "<<Non so cosa fare!>>",
    "<<Young glider, you've been the guardian I don't deserve! Thank you so much!>>": "<<Giovane glider, sei stata la guardiana che non merito! Grazie infinite!>>",
    "Rebuilding The Train": "Ricostruire la Mandria",
    "Mateo has asked me to help him restore what he has lost.": "Mateo mi ha chiesto di aiutarlo a recuperare ciò che ha perso.",
    "Mateo told me that I should speak to Citra, in Eccria.": "Mateo mi ha detto di parlare con Citra, a Eccria.",
    "I paid Citra.": "Ho pagato Citra.",
    "It's time to get back to Mateo.": "È ora di tornare da Mateo.",
    "Mateo has thanked me for helping him start a new herd.": "Mateo mi ha ringraziata per averlo aiutato a iniziare una nuova mandria.",
    "I should ask around to see if anyone's seen the herd.": "Dovrei chiedere in giro per vedere se qualcuno ha visto la mandria.",
    "Do you know where I can find Mateo's herd?": "Sai dove posso trovare la mandria di Mateo?",
    "Don't ask": "Non chiedere",
    '<<"I think I saw a flock out in the desert recently. Mind you, I\'ve also heard rumours of a Sandwyrm out there these days.">>': '<<"Mi pare di aver visto un branco nel deserto di recente. Ma sappi che girano anche voci di un sandwyrm da quelle parti, di questi tempi.">>',
    "<<Young glider! This is a disaster! My herd has gone missing>>": "<<Giovane glider! È un disastro! La mia mandria è scomparsa>>",
    "<<I have no clue what to do! You must help me, glider!.>>": "<<Non ho idea di cosa fare! Devi aiutarmi, glider!>>",
    "<<Styllou's note goes here.>>": "<<Qui va la nota di Styllou.>>",
    "<<You learned what became of my herd? Oh...so my fears weren't baseless.>>": "<<Hai scoperto cosa è successo alla mia mandria? Oh... allora i miei timori non erano infondati.>>",
    "A Shepherd Without A Train": "Un Pastore Senza Mandria",
    "Mateo has asked me to find out what became of his herd.": "Mateo mi ha chiesto di scoprire cosa è successo alla sua mandria.",
    "I should ask around to find any information on Mateo's herd.": "Dovrei chiedere in giro per trovare informazioni sulla mandria di Mateo.",
    "Someone told me taht they last saw the herd in the White Desert, where there had also been sightings of a Sandwyrm.": "Qualcuno mi ha detto che l'ultima volta hanno visto la mandria nel Wash, dove ci sono stati anche avvistamenti di un sandwyrm.",
    "I need to find a way to get inside the Sandwyrm.": "Devo trovare un modo per entrare nel sandwyrm.",
    "I've managed to get inside the Sandwyrm. Let's see if I can find out what happened to the herd.": "Sono riuscita a entrare nel sandwyrm. Vediamo se scopro cosa è successo alla mandria.",
    "I should look for clues to what became of the herd.": "Dovrei cercare indizi su cosa sia successo alla mandria.",
    "I found a note which told of the plot to sacrifice the herd. I should tell Mateo.": "Ho trovato una nota che parlava del complotto per sacrificare la mandria. Dovrei dirlo a Mateo.",
    "I need to tell Mateo what happened.": "Devo dire a Mateo cosa è successo.",
    "I returned to the camp and told Mateo what became of the herd.": "Sono tornata al campo e ho detto a Mateo cosa è successo alla mandria.",
    '<<"This is somewhat embarassing, young glider, but can you help me corrall my herd?">>': '<<"È un po\' imbarazzante, giovane glider, ma puoi aiutarmi a radunare la mia mandria?">>',
    '<<"Please help me find my camels!">>': '<<"Per favore, aiutami a trovare i miei cammelli!">>',
    '<<"Thank you so much! This has been a journey, I\'m sure you\'ll agree! Hah!">>': '<<"Grazie mille! È stato un viaggio, sarai d\'accordo! Hah!">>',
    "Where The Camels Are": "Dove Sono i Cammelli",
    "Mateo told me they've lost track of the herd.": "Mateo mi ha detto che hanno perso traccia della mandria.",
    "There are three camels to find.": "Ci sono tre cammelli da trovare.",
    "I've managed to corrall all the camels.": "Sono riuscita a radunare tutti i cammelli.",
    "I should head back to Mateo.": "Dovrei tornare da Mateo.",
    "Mateo is very grateful that I found his herd.": "Mateo è molto grato che abbia trovato la sua mandria.",

    # Eliisabet / Tough Nut to Crack / Luminescent Adolescent
    '<<"Well, look who’s here! My favourite fellow glider. Funnily enough, I was just thinking about you.">>': '<<"Beh, guarda chi c\'è! La mia glider preferita. Stranamente, stavo proprio pensando a te.">>',
    "I was thinking about you too!": "Stavo pensando anch'io a te!",
    "I didn’t recognize you!": "Non ti avevo riconosciuta!",
    '<<"Were you? Well, sounds like destiny to me. Or at least a bit of good fortune, which frankly is good enough.">>': '<<"Davvero? Beh, sembra destino, a me. O almeno un po\' di buona sorte, che francamente basta e avanza.">>',
    '<<"Ha! Well, how could you be expected to, seeing as how lean and wiry I’ve gotten on my second gliding? I’m going from fighting shape to travelling shape. This old body never lets me down.">>': '<<"Ah! Beh, come potresti, vista quanto magra e nervosa sono diventata in questo secondo volo? Sto passando da forma da combattimento a forma da viaggio. Questo vecchio corpo non mi tradisce mai.">>',
    "Eliisabet chuckles, hands on hips. I ask her why she was thinking of me.": "Eliisabet ridacchia, le mani sui fianchi. Le chiedo perché pensava a me.",
    '<<"Because I was considering all the things I never got to see on my first gliding. I was in such a hurry to get to Eccria and become a guard that my gliding was more of a... piercing. A straight shot to the big city.">>': '<<"Perché stavo considerando tutte le cose che non sono riuscita a vedere durante il mio primo volo. Avevo una tale fretta di arrivare a Eccria e diventare guardia che il mio volo è stato più una... trafittura. Un colpo dritto verso la grande città.">>',
    '<<"Before I knew it, I was years along my path and I’d never seen Hakoa, never swam in underground lakes, never figured out what’s inside a Nimoor Plant...">>': '<<"Prima che me ne accorgessi, erano passati anni del mio cammino e non avevo mai visto Hakoa, mai nuotato in laghi sotterranei, mai capito cosa c\'è dentro una pianta Nimoor...">>',
    "Would you like to?": "Ti piacerebbe?",
    "I don’t think I know either.": "Non credo di saperlo neanch'io.",
    "I ask if she’d like to get to the bottom of what’s inside Nimoor Plants.": "Le chiedo se vorrebbe vedere fino in fondo cosa c'è dentro le piante Nimoor.",
    '<<"You know, I would!">>': '<<"Sai, mi piacerebbe!">>',
    "I tell her I don’t know what’s inside of a Nimoor Plant either.": "Le dico che neanch'io so cosa ci sia dentro una pianta Nimoor.",
    '<<"Well, I’d love to find out!">>': '<<"Beh, mi piacerebbe scoprirlo!">>',
    '<<"I’m sure I must have passed a few of them when I came through the Petrified Forest, but it was daylight then, and the sun makes ‘em close right up.">>': '<<"Sono sicura di averne incrociate alcune quando sono passata per la Foresta Pietrificata, ma era giorno, e il sole le fa richiudere subito.">>',
    '<<"Course I might just have been in too much of a rush to really look. Old habits eh?">>': '<<"Anche se forse avevo troppa fretta per guardare davvero. Vecchie abitudini, eh?">>',
    '<<"Anyhow, don’t think I’ll be making my way back through there anytime soon, sadly. So if you happen to stumble upon one, maybe you could crack it open and let me know what you find?">>': '<<"Comunque, non credo che tornerò di nuovo da quelle parti a breve, purtroppo. Quindi se per caso ti capita di imbatterti in una, magari potresti aprirla e farmi sapere cosa trovi?">>',
    '<<"Something’s got to be making it glow, right?">>': '<<"Qualcosa deve farla brillare, no?">>',
    "Something about her drives me to action and I promise too quickly to show her. I feel compelled to impress her, just a little.": "Qualcosa in lei mi spinge all'azione e prometto troppo in fretta che gliela mostrerò. Mi sento spinta a impressionarla, anche solo un poco.",
    '<<"What! You don’t need to do that, I-- Oh, what am I saying? I’m retired, I’m gliding and I want what I want. Open up a Nimoor Plant and and bring me whatever’s inside.">>': '<<"Cosa! Non devi farlo, io-- Oh, cosa sto dicendo? Sono in pensione, sto facendo il mio volo e voglio quello che voglio. Apri una pianta Nimoor e portami qualunque cosa ci sia dentro.">>',
    '<<"And here’s hoping it isn’t some awful poisoned slime!">>': '<<"E speriamo non sia qualche orrenda melma velenosa!">>',
    "I also hope that.": "Lo spero anch'io.",
    "That could be sort of fun.": "Sarebbe quasi divertente.",
    "I bet that’s exactly what it is.": "Scommetto che è esattamente quello.",
    "I tell her that yes, I also hope I don’t open the Nimoor plant to a burst of caustic ooze. It would be a challenge, I add, to pilot Simoon with skeleton fingers-- not to mention having to bring her news of how it went.": "Le dico che sì, anch'io spero di non aprire la pianta Nimoor solo per beccarmi una scarica di melma caustica. Sarebbe difficile, aggiungo, pilotare Simoon con dita di scheletro-- per non parlare del dover poi raccontarle com'è andata.",
    "I tell her it might be sort of fun to learn that something so pretty would hold a deadly secret, but that I’d be sad to have to return to her and tell her I died in the attempt.": "Le dico che sarebbe quasi divertente scoprire che qualcosa di così carino nasconde un segreto mortale, ma che mi dispiacerebbe tornare da lei a dirle che sono morta nel tentativo.",
    "I say that it probably <i>is</i> filled with deadly poison, and ask if she would like me to forego bringing it back to her, if it is indeed the case.": "Dico che probabilmente <i>è</i> piena di veleno mortale, e chiedo se preferirebbe che evitassi di portargliela, se così fosse.",
    "Eliisabet laughs.": "Eliisabet ride.",
    '<<"Yes, that might be a bit of a letdown.">>': '<<"Sì, sarebbe un po\' una delusione.">>',
    "With my marching orders, I say goodbye to Eliisabet and go on my way.": "Con i miei ordini di marcia, saluto Eliisabet e me ne vado.",
    '<<"Did you find out what\'s inside the Nimoor Plants?">>': '<<"Hai scoperto cosa c\'è dentro le piante Nimoor?">>',
    "Now here I can help! Before she can trail into any wistfulness, I tell her that I already know what’s inside of a Nimoor Plant. She claps her hands together.": "Ecco, qui posso aiutare! Prima che si abbandoni alla nostalgia, le dico che so già cosa c'è dentro una pianta Nimoor. Batte le mani.",
    '<<"You don’t! Do you?">>': '<<"Non è vero! O sì?">>',
    "The thought that I can help Eliisabet using something I happened to have found along the course of my travels warms me. It is a small reminder of the Gliding’s purpose.": "Il pensiero di poter aiutare Eliisabet con qualcosa che ho trovato lungo il cammino mi scalda. È un piccolo promemoria del senso del Volo.",
    "I show her the butterflies I collected.": "Le mostro le farfalle che ho raccolto.",
    '<<"Amazing!">>': '<<"Incredibile!">>',
    "Eliisabet is rapt in wonder.": "Eliisabet è rapita dallo stupore.",
    '<<"Butterflies. Who knew? If you’d given me a thousand chances, I’d never have guessed. I <i>love</i> butterflies, don\'t you?">>': '<<"Farfalle. Chi l\'avrebbe mai detto? Se mi avessero dato mille tentativi, non l\'avrei mai indovinato. <i>Adoro</i> le farfalle, tu no?">>',
    '<<"They flit across the world along their own little paths, dancing alone on the wind, but they seem so pleased whenever they meet up.">>': '<<"Volteggiano per il mondo lungo i loro piccoli sentieri, danzando da sole nel vento, ma sembrano così felici quando si incontrano.">>',
    "Like us, I think.": "Come noi, penso.",
    '<<"A bit like us, I think!">>': '<<"Un po\' come noi, credo!">>',
    "She looks out at the horizon again.": "Guarda di nuovo l'orizzonte.",
    '<<"Thank you, you’re a wonder. And please, take this. Another badge for the Nimoor-picking, butterfly-wrangling young glider who’s been so helpful.">>': '<<"Grazie, sei una meraviglia. E ti prego, prendi questo. Un altro distintivo per la giovane glider raccoglitrice di Nimoor e domatrice di farfalle che mi è stata di tanto aiuto.">>',
    "I take the badge and put it away. I always thought guards were stern and stoic. But Eliisabet is bright, joyful. It is powerful.": "Prendo il distintivo e lo metto via. Ho sempre pensato che le guardie fossero severe e stoiche. Ma Eliisabet è luminosa, gioiosa. È una cosa potente.",
    '<<"Next on my list I’ve got Hakoa; decided it was worth making the trip. Wish me luck, and I’ll wish our paths to cross again.">>': '<<"Il prossimo nella mia lista è Hakoa; ho deciso che vale la pena fare il viaggio. Augurami buona fortuna, e io augurerò che i nostri sentieri si incrocino di nuovo.">>',
    "I have a feeling they will.": "Ho la sensazione che lo faranno.",
    "Good luck to you, too.": "Buona fortuna anche a te.",
    "Hope it happens soon!": "Spero succeda presto!",
    "With a wave, I say goodbye to Eliisabet and go on my way.": "Con un saluto, dico arrivederci a Eliisabet e mi metto in cammino.",
    '<<"I’ll see you soon, I hope. Be well, Sable.">>': '<<"A presto, spero. Stammi bene, Sable.">>',
    "Gather butterflies": "Raccogli farfalle",
    "I collect the butterflies for Eliisabet. She will be keen to see them.": "Raccolgo le farfalle per Eliisabet. Sarà felice di vederle.",
    "Tough Nut To Crack": "Un Osso Duro",
    "Eliisabet asked me to find out what's inside a Nimoor Plant.": "Eliisabet mi ha chiesto di scoprire cosa c'è dentro una pianta Nimoor.",
    "I should head to the Petrified Forest and try to crack open a Nimoor Plant. Eliisabet says they only open their bulbs at night.": "Dovrei andare alla Foresta Pietrificata e provare ad aprire una pianta Nimoor. Eliisabet dice che aprono i loro bulbi solo di notte.",
    "I cracked open a Nimoor Plant and some glowing butterflies flew out! So that's what makes them glow.": "Ho aperto una pianta Nimoor e ne sono volate fuori delle farfalle luminose! Ecco cosa le fa brillare.",
    "I should gather three butterflies for Eliisabet.": "Dovrei raccogliere tre farfalle per Eliisabet.",
    "I should take these butterflies back to Eliisabet.": "Dovrei portare queste farfalle a Eliisabet.",
    "I showed the butterflies to Eliisabet.": "Ho mostrato le farfalle a Eliisabet.",
    "Bones Of Rohana": "Ossa di Rohana",
    '<<"Well, look who it is! What are the chances? You look well, friend.">>': '<<"Beh, guarda chi si vede! Che probabilità c\'erano? Sembri stare bene, amica.">>',
    "Friend! I affect a casual air, and she cannot see me grin as I ask how she’s found herself here.": "Amica! Faccio l'aria disinvolta, e non può vedermi sorridere mentre le chiedo come sia capitata qui.",
    '<<"Well, I planned to go into Hakoa properly, but as much as I have faith in these old bones to hold me, I didn’t fancy roaming in the wastes for too long.">>': '<<"Beh, avevo pianificato di entrare a Hakoa per bene, ma per quanta fiducia abbia in queste vecchie ossa, non mi andava di vagare nelle terre desolate troppo a lungo.">>',
    '<<"Shame, though…I was hoping to grab a few glowing mushrooms. If you can get past the sulphurous pools, they make for quite a snack.">>': '<<"Peccato, però... speravo di prendere qualche fungo luminoso. Se riesci a superare le pozze sulfuree, fanno un bello spuntino.">>',
    "I tell her I had never known them to be edible; I’d seen some among Driss’ supplies, once, and he had told me they were poisonous and never to touch them.": "Le dico che non sapevo fossero commestibili; ne avevo visti tra le provviste di Driss, una volta, e mi aveva detto che erano velenosi e di non toccarli mai.",
    '<<"Oh, they’re very much edible! Found that out one very entertaining evening in Eccria. Let’s just say there’s a case to be made that this is my <i>third</i> gliding, if I count the night I had as my second.">>': '<<"Oh, sono eccome commestibili! L\'ho scoperto durante una serata molto divertente a Eccria. Diciamo che c\'è argomento per dire che questo è il mio <i>terzo</i> volo, se conto la nottata che ho passato come secondo.">>',
    "She laughs at the memories. And I cheekily reevaluate several things about Driss.": "Ride al ricordo. E io rivaluto sfacciatamente diverse cose riguardo a Driss.",
    '<<"You’ve done enough for me of course, but... if you do happen upon any of those fungi-luminescent little fellows, I’d love a few. They tend to grow in a cave at the sulphur pools, far south of here.">>': '<<"Hai già fatto abbastanza per me, ovviamente, ma... se ti capitasse di imbatterti in quei piccoli funghi luminosi, ne vorrei qualcuno. Crescono in una grotta alle pozze sulfuree, lontano a sud da qui.">>',
    '<<"Do let me know if you find those mushrooms!">>': '<<"Fammi sapere se trovi quei funghi!">>',
    "When I return, Eliisabet is sharpening a knife with a carved hilt and humming a tune that seems at once new and familiar. The sound of her voice is calming, then, but booms a welcome.": "Quando torno, Eliisabet sta affilando un coltello dall'impugnatura intagliata e canticchia una melodia che sembra al tempo stesso nuova e familiare. Il suono della sua voce è calmante, poi, ma esplode in un benvenuto.",
    '<<"She returns! Triumphant, I bet.">>': '<<"Ritorna! Trionfante, scommetto.">>',
    "I confirm as much with a handful of mushrooms and she raises them to her face to smell. As she inhales, I look at the worn edges of her mask.": "Lo confermo con una manciata di funghi e lei se li avvicina al viso per annusarli. Mentre inspira, osservo i bordi consumati della sua maschera.",

    # Llhor / Searching for Llhor
    "The Atomic Priest leans forward in a way they must think is inviting.": "Il Sacerdote Atomico si china in avanti in un modo che ritiene invitante.",
    "And I suppose they're right, because here I am.": "E suppongo che abbia ragione, perché eccomi qui.",
    '<<"Glider! We\'ve a task for you, if you\'re able. And interested, of course.">>': '<<"Glider! Abbiamo un compito per te, se puoi. E se ti interessa, ovviamente.">>',
    '<<"Gliders tend to be interested in <i>tasks</i>.">>': '<<"Le Glider tendono a essere interessate ai <i>compiti</i>.">>',
    "I've never known quite how to feel about the Atomic Priesthood.": "Non ho mai saputo bene come sentirmi riguardo al Sacerdozio Atomico.",
    "As a child, I had been both fearful and fascinated, watching them go about their mysterious business and making up all kinds of things about them in my head.": "Da bambina ne ero al tempo stesso impaurita e affascinata, guardandoli svolgere i loro misteriosi affari e inventandomi ogni sorta di cose su di loro nella mia testa.",
    "Today, I understand that they are an order like any other...": "Oggi capisco che sono un ordine come qualunque altro...",
    "...only more severe, more insular and dedicated to collective caution in a way that increasingly feels more like paranoia than reason.": "...solo più severo, più insulare e dedito a una cautela collettiva che sempre più sembra paranoia che ragione.",
    "Still, I do mostly like a task.": "Eppure, in genere mi piace un compito.",
    '<<"Are you familiar with Llhor the Fabulist?">>': '<<"Conosci Llhor la Favolatrice?">>',
    "I am!": "Sì!",
    "Never heard of her!": "Mai sentita!",
    "I tell them that I've met Llhor before, at her camp.": "Gli dico che ho già incontrato Llhor, al suo campo.",
    '<<"Perfect! You were the right selection for the task, I think.">>': '<<"Perfetto! Eri la scelta giusta per il compito, credo.">>',
    "I lie that I've never heard of her.": "Mento dicendo di non averla mai sentita nominare.",
    '<<"Is that true?">>': '<<"È vero?">>',
    "The Atomic Priest nods and goes silent for a moment.": "Il Sacerdote Atomico annuisce e tace per un momento.",
    '<<"Unfortunate.">>': '<<"Spiacevole.">>',
    '<<"But no matter! We still require the task.">>': '<<"Ma non importa! Il compito è ancora necessario.">>',
    "I tell the Priest I've never heard of Llhor the Fabulist.": "Dico al Sacerdote che non ho mai sentito parlare di Llhor la Favolatrice.",
    '<<"Then this is the perfect task for you! Because you <i>will</i> know Llhor the Fabulist at its end.">>': '<<"Allora è il compito perfetto per te! Perché alla fine <i>conoscerai</i> Llhor la Favolatrice.">>',
    "Sounds reasonable. I ask what the task is.": "Mi sembra ragionevole. Chiedo qual è il compito.",
    '<<"We need you to find Llhor. And when you do, convey that we would like to invite her back to Eccria.">>': '<<"Vogliamo che tu trovi Llhor. E quando lo farai, comunicale che vorremmo invitarla a tornare a Eccria.">>',
    '<<"We... miss her. Quite a lot, in fact.">>': '<<"Ci... manca. Parecchio, in realtà.">>',
    "It may be the most emotion I've heard from a member of the Priesthood, and it seems quite legitimate. I wonder what sort of relationship Llhor has with them.": "Potrebbe essere la più grande emozione che abbia mai sentito da un membro del Sacerdozio, e sembra autentica. Mi chiedo che rapporto abbia Llhor con loro.",
    "Tell me more about Llhor!": "Dimmi di più su Llhor!",
    "Why did she leave?": "Perché se n'è andata?",
    "I ask them to tell me more about Llhor.": "Gli chiedo di dirmi di più su Llhor.",
    '<<"She has been among our strongest voices, turning warning into whimsy and safety into song. She speaks the language of the common, to convey the words of the wise.">>': '<<"È stata tra le nostre voci più forti, trasformando l\'avvertimento in fantasia e la sicurezza in canzone. Parla la lingua del popolo, per trasmettere le parole dei saggi.">>',
    "I ask why Llhor left Eccria in the first place.": "Chiedo perché Llhor abbia lasciato Eccria in primo luogo.",
    '<<"According to her, she wished to \'clear her mind\'. We are uncertain what she means by it, but we hope that she does not clear her mind of all that she has done for us.">>': '<<"Secondo lei, voleva \'schiarirsi le idee\'. Non siamo sicuri di cosa intenda con questo, ma speriamo non si schiarisca le idee da tutto quello che ha fatto per noi.">>',
    "I ask what she's done.": "Chiedo cosa abbia fatto.",
    '<<"She has spread our message to those places where we who are not her cannot reach. A strong voice in the Atomic Priesthood.">>': '<<"Ha diffuso il nostro messaggio nei luoghi dove noi che non siamo lei non possiamo arrivare. Una voce forte nel Sacerdozio Atomico.">>',
    "Perfect. I'm off!": "Perfetto. Vado!",
    "Where do you think Llhor is?": "Dove pensi che sia Llhor?",
    "I tell the Atomic Priest I'll try to find Llhor and go to leave. The Priest bows a farewell.": "Dico al Sacerdote Atomico che proverò a trovare Llhor e mi accingo ad andare. Il Sacerdote si inchina in congedo.",
    '<<"If you aren\'t sure where to start, it may be wise to speak with innkeepers at the Beetle Stations. Llhor carries our messages all across the world.">>': '<<"Se non sei sicura da dove iniziare, può essere saggio parlare con i locandieri delle Stazioni degli Scarabei. Llhor porta i nostri messaggi in tutto il mondo.">>',
    "I thank them for the advice and wave goodbye.": "Lo ringrazio per il consiglio e lo saluto.",
    '<<"Any progress on finding Llhor, Glider? We do miss her.">>': '<<"Progressi sulla ricerca di Llhor, Glider? Davvero ci manca.">>',
    "I tell them I'm still working on it.": "Gli dico che ci sto ancora lavorando.",
    '<<"We don’t know what you said to her, Glider. But we are grateful that you said it.”>>': '<<"Non sappiamo cosa le hai detto, Glider. Ma siamo grati che gliel\'abbia detto.">>',
    '<<”Llhor has returned with a renewed passion. And we credit you.”>>': '<<"Llhor è tornata con rinnovata passione. E il merito è tuo.">>',
    '<<”So thank you, Glider. And be safe.”>>': '<<"Quindi grazie, Glider. E mettiti al sicuro.">>',
    "Do you know where Llhor is?": "Sai dove si trovi Llhor?",
    '<<"Ah! You\'re looking for Llhor? Love her, she\'s great. Think last I heard she was on her way to the Sodics. Big place. Good place to empty the ol\' thought-bucket.">>': '<<"Ah! Cerchi Llhor? La adoro, è fantastica. Mi pare che l\'ultima volta fosse diretta verso i Sodici. Posto grande. Buon posto per svuotare il vecchio secchio dei pensieri.">>',
    "I thank her for the help.": "La ringrazio per l'aiuto.",
    '<<"Can\'t tell you where she is right now, but when I saw her, she was looking for the Sleeping Singers. They\'re a set of stone whales, can\'t miss them.">>': '<<"Non posso dirti dove sia adesso, ma quando l\'ho vista cercava i Cantori Dormienti. Sono delle balene di pietra, impossibile non vederle.">>',
    '<<"Llhor? Haven\'t seen her in <i>ages</i>. Like, actual years. I think at the time she was following the path of the Archer.">>': '<<"Llhor? Non la vedo da <i>secoli</i>. Cioè, anni veri. Mi pare che all\'epoca seguisse la via dell\'Arciere.">>',
    "If I had any doubts that I would recognize the fabled Llhor, they vanished at the sight of her mask.": "Se avevo dei dubbi sul fatto di riconoscere la mitica Llhor, sono svaniti alla vista della sua maschera.",
    "A face turns.": "Un volto si volta.",
    '<<"You\'re looking for me, aren\'t you?">>': '<<"Mi stai cercando, vero?">>',
    "The Atomic Priesthood is looking for you.": "Il Sacerdozio Atomico ti sta cercando.",
    "I'd like to meet you. I'm a fan.": "Volevo conoscerti. Sono una fan.",
    "Just a fellow traveller.": "Solo una compagna di viaggio.",
    "I tell Llhor that I'm here on behalf of the Atomic Priesthood.": "Dico a Llhor che sono qui per conto del Sacerdozio Atomico.",
    "Searching For Llhor": "In Cerca di Llhor",
    "Shar Varana in Eccria wanted me to track down Llhor, the legendary fabulist. They said I should ask the innkeepers at the beetle stations if they know anything about Llhor's whereabouts.": "Shar Varana a Eccria voleva che rintracciassi Llhor, la leggendaria favolatrice. Mi ha detto di chiedere ai locandieri delle stazioni degli scarabei se sanno qualcosa su dove si trovi Llhor.",
    "Ifaa at Burnt Oak Station said Llhor was searching for 'somewhere desolate, somewhere vast'. She suggested the Sodic Wastes.": "Ifaa alla Burnt Oak Station ha detto che Llhor cercava 'un posto desolato, un posto vasto'. Ha suggerito il Sodic Waste.",
    "Ofuu at Marrow Bone Station told me to look for the Sleeping Singers, a set of stone whales.": "Ofuu alla Marrow Bone Station mi ha detto di cercare i Cantori Dormienti, delle balene di pietra.",
    "Afii at Seven Sisters Station said Llhor had been seeking to follow the path of the Archer.": "Afii alla Stazione Sette Sorelle ha detto che Llhor cercava di seguire la via dell'Arciere.",
    "Ask about Llhor at Burnt Oak Station.": "Chiedi di Llhor alla Burnt Oak Station.",
    "Ask about Llhor at Marrow Bone Station.": "Chiedi di Llhor alla Marrow Bone Station.",
    "Ask about Llhor at Seven Sisters Station.": "Chiedi di Llhor alla Stazione Sette Sorelle.",
    "Find Llhor.": "Trova Llhor.",
    "I found Llhor camping out in the Salt Plains. I should go and tell her she's wanted in Eccria.": "Ho trovato Llhor accampata nelle Saline. Dovrei andare a dirle che la vogliono a Eccria.",
    "After spending the evening at Llhor's camp, I convinced her to return to Eccria.": "Dopo aver passato la sera al campo di Llhor, l'ho convinta a tornare a Eccria.",
    "I should speak to Shar Varana now that Llhor has returned.": "Dovrei parlare con Shar Varana ora che Llhor è tornata.",
    "Shar Varana was very grateful for my help in convincing Llhor.": "Shar Varana è stato molto grato per il mio aiuto nel convincere Llhor.",
    "Glowworm": "Verme Luminoso",
    "Nozi's Nibbles": "Gli Spuntini di Nozi",
    "Gather glow worms": "Raccogli vermi luminosi",
    "More than a little pleased with my success, I gather up the glowworms and tuck them away. Worms for a wyrm.": "Più che soddisfatta del mio successo, raccolgo i vermi luminosi e li metto via. Vermi per un wyrm.",
    "Do you know where I can find some glowworms?": "Sai dove posso trovare dei vermi luminosi?",
    '<<"Yes, yes, absolutely I do! There\'s a cave far to the south of here, just packed with the sinister little creeps.">>': '<<"Sì, sì, certo che lo so! C\'è una grotta molto a sud di qui, piena zeppa di quei piccoli sinistri viscidi.">>',
    "Sinister little creeps.": "Sinistri piccoli viscidi.",
    '<<"I hate them. They\'re just... ugh, awful! But unfortunately, they\'re of use sometimes, so I\'ve become quite practised at catching them.">>': '<<"Li odio. Sono... ugh, orribili! Ma purtroppo a volte tornano utili, quindi mi sono fatta piuttosto pratica a catturarli.">>',
    "I ask if she might be able to help and the response is a shudder.": "Le chiedo se potrebbe aiutare e la risposta è un brivido.",
    '<<"Absolutely not. But I can advise: you\'ll need to get them down from where they nest on the roof of the cave. To do that, look for sulfurous rocks lying around nearby. Do you want to write this down?">>': '<<"Assolutamente no. Ma posso consigliare: devi farli scendere da dove si annidano sul soffitto della grotta. Per farlo, cerca rocce sulfuree in giro lì vicino. Vuoi prendere appunti?">>',
    "I tell her I'm taking mental notes.": "Le dico che sto prendendo appunti mentali.",
    '<<"Well, you want to look for sulfurous rocks and get them wet. They\'ll start smoking, and that should be enough to knock the glowworms out and net you your awful, slimy quarry.">>': '<<"Bene, devi cercare rocce sulfuree e bagnarle. Inizieranno a fumare, e dovrebbe bastare per stordire i vermi luminosi e portarti la tua orribile, viscida preda.">>',
    "Rather than put her through more, I offer my thanks and move along.": "Per non farla soffrire ulteriormente, le porgo i miei ringraziamenti e proseguo.",
    '<<"I don\'t, I\'m afraid. The innkeeper might know!">>': '<<"Non lo so, mi spiace. Forse il locandiere lo sa!">>',
}

def main():
    csv_in = 'translations/ink_strings.csv'
    rows = list(csv.DictReader(open(csv_in)))
    applied = 0
    for r in rows:
        if r['en'] in T and not r['it']:
            r['it'] = T[r['en']]
            applied += 1
    with open(csv_in, 'w', newline='', encoding='utf-8') as f:
        w = csv.DictWriter(f, fieldnames=['path', 'en', 'it'], quoting=csv.QUOTE_ALL)
        w.writeheader()
        w.writerows(rows)
    total_translated = sum(1 for r in rows if r['it'])
    print(f"Applied {applied} new translations from this batch")
    print(f"Total translated: {total_translated}/{len(rows)}")

if __name__ == '__main__':
    main()
